using ArchStudy.Ddd.Domain;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Ddd.Application;

public class AccountApplicationService(
    IAccountRepository accounts,
    ITransactionLog transactionLog,
    IUnitOfWork uow,
    TransferDomainService transferService)
{
    public async Task<AccountResponse> OpenAccountAsync(string owner, CancellationToken ct)
    {
        var account = Account.Open(owner);
        await accounts.AddAsync(account, ct);
        await uow.CommitAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse?> GetAccountAsync(Guid id, CancellationToken ct) =>
        (await accounts.LoadAsync(id, ct)) is { } a ? Map(a) : null;

    public async Task<IReadOnlyList<TransactionResponse>> GetStatementAsync(Guid id, CancellationToken ct)
    {
        var entries = await transactionLog.ListByAccountAsync(id, ct);
        return entries
            .Select(t => new TransactionResponse(t.Id, t.AccountId, t.Type, t.Amount.Amount, t.Timestamp, t.RelatedAccountId))
            .ToList();
    }

    public async Task<AccountResponse> DepositAsync(Guid id, decimal amount, CancellationToken ct)
    {
        var account = await accounts.LoadAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");
        var money = Money.Of(amount);
        account.Deposit(money);
        await transactionLog.AppendAsync(Transaction.Of(account.Id, TransactionType.Deposit, money), ct);
        await uow.CommitAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse> WithdrawAsync(Guid id, decimal amount, CancellationToken ct)
    {
        var account = await accounts.LoadAsync(id, ct) ?? throw new KeyNotFoundException("Account not found");
        var money = Money.Of(amount);
        account.Withdraw(money);
        await transactionLog.AppendAsync(Transaction.Of(account.Id, TransactionType.Withdrawal, money), ct);
        await uow.CommitAsync(ct);
        return Map(account);
    }

    public async Task TransferAsync(Guid fromId, Guid toId, decimal amount, CancellationToken ct)
    {
        var from = await accounts.LoadAsync(fromId, ct) ?? throw new KeyNotFoundException("Source account not found");
        var to = await accounts.LoadAsync(toId, ct) ?? throw new KeyNotFoundException("Destination account not found");
        var money = Money.Of(amount);
        transferService.Transfer(from, to, money);

        await transactionLog.AppendAsync(Transaction.Of(from.Id, TransactionType.TransferOut, money, to.Id), ct);
        await transactionLog.AppendAsync(Transaction.Of(to.Id, TransactionType.TransferIn, money, from.Id), ct);
        await uow.CommitAsync(ct);
    }

    private static AccountResponse Map(Account a) => new(a.Id, a.Owner, a.Balance.Amount, a.CreatedAt);
}

using ArchStudy.Ddd.Application;
using ArchStudy.Ddd.Domain;
using ArchStudy.Ddd.Infrastructure;
using ArchStudy.Ddd.Presentation;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Ddd;

public static class DddModule
{
    public static IServiceCollection AddDddModule(this IServiceCollection services)
    {
        services.AddDbContext<DddDbContext>(o => o.UseSqlite("Data Source=archstudy-ddd.db"));
        services.AddScoped<IAccountRepository, AccountRepository>();
        services.AddScoped<ITransactionLog, TransactionLog>();
        services.AddScoped<IUnitOfWork, UnitOfWork>();
        services.AddScoped<TransferDomainService>();
        services.AddScoped<AccountApplicationService>();
        return services;
    }

    public static IEndpointRouteBuilder MapDddModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/ddd").WithTags("DDD");
        DddEndpoints.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<DddDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

namespace ArchStudy.Ddd.Domain;

public class Account
{
    public Guid Id { get; private set; }
    public string Owner { get; private set; } = string.Empty;
    public Money Balance { get; private set; }
    public DateTime CreatedAt { get; private set; }

    private Account() { }

    public static Account Open(string owner)
    {
        if (string.IsNullOrWhiteSpace(owner))
            throw new ArgumentException("Owner is required", nameof(owner));

        return new Account
        {
            Id = Guid.NewGuid(),
            Owner = owner,
            Balance = Money.Zero,
            CreatedAt = DateTime.UtcNow,
        };
    }

    public void Deposit(Money amount)
    {
        if (!amount.IsPositive) throw new ArgumentException("Amount must be positive");
        Balance = Balance.Plus(amount);
    }

    public void Withdraw(Money amount)
    {
        if (!amount.IsPositive) throw new ArgumentException("Amount must be positive");
        if (Balance.IsLessThan(amount)) throw new InsufficientFundsException(Id);
        Balance = Balance.Minus(amount);
    }
}

public sealed class InsufficientFundsException(Guid accountId)
    : InvalidOperationException($"Account {accountId} has insufficient funds");

namespace ArchStudy.Ddd.Domain;

public interface IAccountRepository
{
    Task<Account?> LoadAsync(Guid id, CancellationToken ct);
    Task AddAsync(Account account, CancellationToken ct);
}

public interface ITransactionLog
{
    Task<IReadOnlyList<Transaction>> ListByAccountAsync(Guid accountId, CancellationToken ct);
    Task AppendAsync(Transaction transaction, CancellationToken ct);
}

public interface IUnitOfWork
{
    Task CommitAsync(CancellationToken ct);
}

namespace ArchStudy.Ddd.Domain;

public sealed record Money(decimal Amount)
{
    public static Money Zero { get; } = new(0m);

    public bool IsPositive => Amount > 0m;

    public Money Plus(Money other) => new(Amount + other.Amount);
    public Money Minus(Money other) => new(Amount - other.Amount);
    public bool IsLessThan(Money other) => Amount < other.Amount;

    public static Money Of(decimal amount)
    {
        if (amount <= 0) throw new ArgumentException("Money must be positive", nameof(amount));
        return new Money(amount);
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.Ddd.Domain;

public class Transaction
{
    public Guid Id { get; private set; }
    public Guid AccountId { get; private set; }
    public TransactionType Type { get; private set; }
    public Money Amount { get; private set; }
    public DateTime Timestamp { get; private set; }
    public Guid? RelatedAccountId { get; private set; }

    private Transaction() { }

    public static Transaction Of(Guid accountId, TransactionType type, Money amount, Guid? relatedAccountId = null) =>
        new()
        {
            Id = Guid.NewGuid(),
            AccountId = accountId,
            Type = type,
            Amount = amount,
            Timestamp = DateTime.UtcNow,
            RelatedAccountId = relatedAccountId,
        };
}

namespace ArchStudy.Ddd.Domain;

public class TransferDomainService
{
    public void Transfer(Account from, Account to, Money amount)
    {
        if (from.Id == to.Id) throw new ArgumentException("Accounts must differ");
        from.Withdraw(amount);
        to.Deposit(amount);
    }
}

using ArchStudy.Ddd.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Ddd.Infrastructure;

public class DddDbContext(DbContextOptions<DddDbContext> options) : DbContext(options)
{
    public DbSet<Account> Accounts => Set<Account>();
    public DbSet<Transaction> Transactions => Set<Transaction>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Account>(b =>
        {
            b.HasKey(a => a.Id);
            b.Property(a => a.Owner).IsRequired();
            b.OwnsOne(a => a.Balance, m => m.Property(p => p.Amount).HasColumnName("Balance"));
            b.Property(a => a.CreatedAt);
        });

        modelBuilder.Entity<Transaction>(b =>
        {
            b.HasKey(t => t.Id);
            b.Property(t => t.AccountId);
            b.Property(t => t.Type);
            b.OwnsOne(t => t.Amount, m => m.Property(p => p.Amount).HasColumnName("Amount"));
            b.Property(t => t.Timestamp);
            b.Property(t => t.RelatedAccountId);
        });
    }
}

using ArchStudy.Ddd.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Ddd.Infrastructure;

public class AccountRepository(DddDbContext db) : IAccountRepository
{
    public Task<Account?> LoadAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task AddAsync(Account account, CancellationToken ct) =>
        await db.Accounts.AddAsync(account, ct);
}

public class TransactionLog(DddDbContext db) : ITransactionLog
{
    public async Task<IReadOnlyList<Transaction>> ListByAccountAsync(Guid accountId, CancellationToken ct) =>
        await db.Transactions
            .Where(t => t.AccountId == accountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

    public async Task AppendAsync(Transaction transaction, CancellationToken ct) =>
        await db.Transactions.AddAsync(transaction, ct);
}

public class UnitOfWork(DddDbContext db) : IUnitOfWork
{
    public Task CommitAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.Ddd.Application;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Ddd.Presentation;

public static class DddEndpoints
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (CreateAccountRequest req, AccountApplicationService svc, CancellationToken ct) =>
        {
            var account = await svc.OpenAccountAsync(req.Owner, ct);
            return Results.Created($"/ddd/accounts/{account.Id}", account);
        });

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (Guid id, AccountApplicationService svc, CancellationToken ct) =>
        {
            var account = await svc.GetAccountAsync(id, ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });

        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (Guid id, AccountApplicationService svc, CancellationToken ct) =>
            Results.Ok(await svc.GetStatementAsync(id, ct)));

        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (Guid id, DepositRequest req, AccountApplicationService svc, CancellationToken ct) =>
            Results.Ok(await svc.DepositAsync(id, req.Amount, ct)));

        group.MapPost("/accounts/{id:guid}/withdrawals", async Task<IResult> (Guid id, WithdrawalRequest req, AccountApplicationService svc, CancellationToken ct) =>
            Results.Ok(await svc.WithdrawAsync(id, req.Amount, ct)));

        group.MapPost("/transfers", async Task<IResult> (TransferRequest req, AccountApplicationService svc, CancellationToken ct) =>
        {
            await svc.TransferAsync(req.FromAccountId, req.ToAccountId, req.Amount, ct);
            return Results.NoContent();
        });
    }
}
